values.content:
=Generate a complete onboarding package for this new employee:

Name: {{ $json.employee_name }}
Role: {{ $json.role }}
Department: {{ $json.department }}
Start Date: {{ $json.start_date }}
Manager: {{ $json.manager_name }}
Company: {{ $json.company_name }}

Return a JSON object with these exact fields:
{
  "welcome_subject": "Email subject line (warm, exciting, personalized)",
  "welcome_email_html": "Full HTML welcome email body (professional, warm, include: welcome message, what to expect on Day 1, 3 key tips to hit the ground running, manager introduction, open door policy note, sign off from HR)",
  "day7_subject": "Subject line for 7-day check-in email",
  "day7_email_html": "HTML body for Day 7 check-in (ask how first week went, share 3 resources, next 30-day focus areas)",
  "day30_subject": "Subject line for 30-day milestone email",
  "day30_email_html": "HTML body for Day 30 milestone (celebrate progress, collect feedback, set 60-day goals)",
  "slack_announcement": "Slack message announcing the new hire to the team (friendly, include role, fun fact placeholder, encourage team to say hi, max 3 sentences)",
  "manager_briefing": "Short manager briefing — 5 bullet points of what to do in the employee first week",
  "onboarding_checklist": ["task1", "task2", "task3", "task4", "task5", "task6", "task7", "task8"],
  "buddy_suggestion": "One paragraph suggestion for what to look for in an onboarding buddy for this role/department",
  "first_week_goals": ["goal1", "goal2", "goal3"]
}

parameters.jsCode:
const item = $input.first();
const raw = item.json.message?.content || item.json.choices?.[0]?.message?.content || '';

let parsed = {};
try {
  const clean = raw.replace(/```json/gi, '').replace(/```/g, '').trim();
  parsed = JSON.parse(clean);
} catch (e) {
  parsed = {
    welcome_subject: `Welcome to the team, ${$('Set — Normalize Fields').first().json.employee_name}! 🎉`,
    welcome_email_html: `<p>Hi ${$('Set — Normalize Fields').first().json.employee_name},</p><p>Welcome aboard! We're thrilled to have you joining us as ${$('Set — Normalize Fields').first().json.role} in the ${$('Set — Normalize Fields').first().json.department} department. Your start date is ${$('Set — Normalize Fields').first().json.start_date}.</p><p>Your manager ${$('Set — Normalize Fields').first().json.manager_name} will be in touch soon with more details. In the meantime, feel free to reply to this email with any questions.</p><p>Best regards,<br>HR Team</p>`,
    day7_subject: `How's your first week going, ${$('Set — Normalize Fields').first().json.employee_name}?`,
    day7_email_html: `<p>Hi ${$('Set — Normalize Fields').first().json.employee_name},</p><p>You've completed your first week! We'd love to hear how it's going. Please reply with any feedback or questions.</p>`,
    day30_subject: `30-Day Milestone — You're crushing it! 🚀`,
    day30_email_html: `<p>Hi ${$('Set — Normalize Fields').first().json.employee_name},</p><p>Congratulations on completing your first 30 days! We're proud of your progress. Let's set some goals for the next 60 days.</p>`,
    slack_announcement: `🎉 Please welcome ${$('Set — Normalize Fields').first().json.employee_name} who is joining us as ${$('Set — Normalize Fields').first().json.role} in ${$('Set — Normalize Fields').first().json.department}! Say hi and make them feel at home. 👋`,
    manager_briefing: '• Schedule a Day 1 welcome call\n• Share team org chart\n• Set up tool access\n• Assign an onboarding buddy\n• Review 30-day expectations',
    onboarding_checklist: ['Send welcome email', 'Set up email account', 'Add to Slack channels', 'Set up laptop', 'Schedule Day 1 orientation', 'Assign onboarding buddy', 'Share company handbook', 'Schedule 30-day check-in'],
    buddy_suggestion: 'Look for a team member who has been with the company 6-12 months, has strong communication skills, and is in a similar role or adjacent department.',
    first_week_goals: ['Complete IT setup and tool access', 'Meet all direct team members', 'Understand the 30-60-90 day plan']
  };
}

const setNode = $('Set — Normalize Fields').first().json;

return [{
  json: {
    ...setNode,
    ...parsed,
    parse_error: Object.keys(parsed).length === 0
  }
}];
